import { MathJaxProvider } from '@yozora/react-markdown'
import React from 'react'
import Transition from './Transition'

export interface TransitionLinkLayoutProps {
  children: React.ReactNode
  location: {
    key: string
    pathname: string
  }
}

export function TransitionLinkLayout(
  props: TransitionLinkLayoutProps,
): React.ReactElement {
  const { children, location } = props
  return (
    <MathJaxProvider mathjaxSrc="https://cdn.jsdelivr.net/npm/mathjax@2.7.5/MathJax.js?config=TeX-MML-AM_CHTML">
      <Transition location={location}>{children}</Transition>
    </MathJaxProvider>
  )
}

export default TransitionLinkLayout
